14	    const liveNeighbors = countLiveNeighbors(cell, cells);
15	    return liveNeighbors === 2 || liveNeighbors === 3;
16	  });
17	
18	  const deadCandidates: Cell[] = [];
19	  for (const [x, y] of cells) {
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        if (dx === 0 && dy === 0) continue;
23	        const nx = x + dx;
24	        const ny = y + dy;
25	        if (cells.some(([cx, cy]) => cx === nx && cy === ny)) continue;
26	        if (deadCandidates.some(([cx, cy]) => cx === nx && cy === ny)) continue;
27	        if (countLiveNeighbors([nx, ny], cells) === 3) {
28	          deadCandidates.push([nx, ny]);
29	        }
30	      }
31	    }
32	  }
33	
34	  return [...survivors, ...deadCandidates];
